1089 void VPlanTransforms::addMinimumVectorEpilogueIterationCheck(
1090     VPlan &Plan, Value *TripCount, Value *VectorTripCount,
1091     bool RequiresScalarEpilogue, ElementCount EpilogueVF, unsigned EpilogueUF,
1092     unsigned MainLoopStep, unsigned EpilogueLoopStep, ScalarEvolution &SE) {
1093   // Add the minimum iteration check for the epilogue vector loop.
1094   VPValue *TC = Plan.getOrAddLiveIn(TripCount);
1095   VPBuilder Builder(cast<VPBasicBlock>(Plan.getEntry()));
1096   VPValue *VFxUF = Builder.createExpandSCEV(SE.getElementCount(
1097       TripCount->getType(), (EpilogueVF * EpilogueUF), SCEV::FlagNUW));
1098   VPValue *Count = Builder.createNaryOp(
1099       Instruction::Sub, {TC, Plan.getOrAddLiveIn(VectorTripCount)},
1100       DebugLoc::getUnknown(), "n.vec.remaining");
1101 
1102   // Generate code to check if the loop's trip count is less than VF * UF of
1103   // the vector epilogue loop.
1104   auto P = RequiresScalarEpilogue ? ICmpInst::ICMP_ULE : ICmpInst::ICMP_ULT;
1105   auto *CheckMinIters = Builder.createICmp(
1106       P, Count, VFxUF, DebugLoc::getUnknown(), "min.epilog.iters.check");
1107   VPInstruction *Branch =
1108       Builder.createNaryOp(VPInstruction::BranchOnCond, CheckMinIters);
1109 
1110   // We assume the remaining `Count` is equally distributed in
1111   // [0, MainLoopStep)
1112   // So the probability for `Count < EpilogueLoopStep` should be
1113   // min(MainLoopStep, EpilogueLoopStep) / MainLoopStep
1114   // TODO: Improve the estimate by taking the estimated trip count into
1115   // consideration.
1116   unsigned EstimatedSkipCount = std::min(MainLoopStep, EpilogueLoopStep);
1117   const uint32_t Weights[] = {EstimatedSkipCount,
1118                               MainLoopStep - EstimatedSkipCount};
1119   MDBuilder MDB(Plan.getContext());
1120   MDNode *BranchWeights =
1121       MDB.createBranchWeights(Weights, /*IsExpected=*/false);
1122   Branch->setMetadata(LLVMContext::MD_prof, BranchWeights);
1123 }
