1139 /// Find the ComputeReductionResult recipe for \p PhiR, looking through selects
1140 /// inserted for predicated reductions or tail folding.
1141 static VPInstruction *findComputeReductionResult(VPReductionPHIRecipe *PhiR) {
1142   VPValue *BackedgeVal = PhiR->getBackedgeValue();
