1267     auto *NewSel = MiddleBuilder.createSelect(AnyNaNLane, RedPhiR,
1268                                               RdxResult->getOperand(0));
1269     RdxResult->setOperand(0, NewSel);
1270     assert(!RdxResults.contains(RdxResult) && "RdxResult already used");
1271     RdxResults.insert(RdxResult);
1272   }
1273 
1274   auto *LatchExitingBranch = LatchVPBB->getTerminator();
1275   assert(match(LatchExitingBranch, m_BranchOnCount(m_VPValue(), m_VPValue())) &&
